    private class HybridWebViewClient extends WebViewClient {

        @Override
        public void onPageStarted(WebView view, String url, Bitmap favicon) {
            super.onPageStarted(view, url, favicon);
            progressBar.setVisibility(View.VISIBLE);
        }

        @Override
        public void onPageFinished(WebView view, String url) {
            super.onPageFinished(view, url);
            progressBar.setVisibility(View.GONE);
            swipeRefreshLayout.setRefreshing(false);
            injectBridgeHelperScript();
        }

        @Override
        public boolean shouldOverrideUrlLoading(WebView view, WebResourceRequest request) {
            String url = request.getUrl().toString();

            // Handle external URLs
            if (url.startsWith("tel:") || url.startsWith("mailto:") || url.startsWith("sms:")) {
                Intent intent = new Intent(Intent.ACTION_VIEW, Uri.parse(url));
                startActivity(intent);
                return true;
            }

            // Handle deep links for payment apps
            if (url.startsWith("upi:") || url.startsWith("gpay:") ||
                    url.startsWith("paytm:") || url.startsWith("phonepe:")) {
                try {
                    Intent intent = new Intent(Intent.ACTION_VIEW, Uri.parse(url));
                    startActivity(intent);
                } catch (Exception e) {
                    Toast.makeText(MainActivity.this,
                            "Payment app not found", Toast.LENGTH_SHORT).show();
                }
                return true;
            }

            // Handle intent:// URLs
            if (url.startsWith("intent://")) {
                try {
                    Intent intent = Intent.parseUri(url, Intent.URI_INTENT_SCHEME);
                    if (intent.resolveActivity(getPackageManager()) != null) {
                        startActivity(intent);
                    } else {
                        String fallbackUrl = intent.getStringExtra("browser_fallback_url");
                        if (fallbackUrl != null) {
                            view.loadUrl(fallbackUrl);
                        }
                    }
                } catch (Exception e) {
                    Log.e(TAG, "Error handling intent URL", e);
                }
                return true;
            }

            // Keep our domain in WebView
            if (url.contains("your-mobile-website.com")) {
                return false;
            }

            // Open external URLs in browser
            Intent intent = new Intent(Intent.ACTION_VIEW, Uri.parse(url));
            startActivity(intent);
            return true;
        }

        @Override
        public void onReceivedError(WebView view, WebResourceRequest request,
                                    WebResourceError error) {
            super.onReceivedError(view, request, error);
            if (request.isForMainFrame()) {
                String errorHtml = "<html><body style='display:flex;justify-content:center;" +
                        "align-items:center;height:100vh;font-family:sans-serif;'>" +
                        "<div style='text-align:center;'>" +
                        "<h2>Connection Error</h2>" +
                        "<p>Unable to load the page. Please check your connection.</p>" +
                        "<button onclick='window.location.reload()' " +
                        "style='padding:12px 24px;font-size:16px;border:none;" +
                        "background:#007AFF;color:white;border-radius:8px;'>Retry</button>" +
                        "</div></body></html>";
                view.loadData(errorHtml, "text/html", "UTF-8");
            }
        }
    }

    // ============================================
